<template>
  <v-layout column>
    <v-flex xs12 sm12>
      <v-select :items="statusLabels" item-text="text" item-value="status" v-model="status" @input="getRunners()"/>
    </v-flex>
  <v-list three-line>
    <template v-for="(runner, index) in runners">
      <v-list-tile
        :key="index"
        @click="runnerInfo (runner.id)"
      >
        <v-list-tile-content>
          <v-list-tile-title v-html="runner.name"></v-list-tile-title>
          <v-list-tile-sub-title v-html="runner.birthday"></v-list-tile-sub-title>
          <v-list-tile-sub-title v-html="runner.organization"></v-list-tile-sub-title>
        </v-list-tile-content>
      </v-list-tile>
    </template>
    <the-pagination />
  </v-list>
  </v-layout>
</template>

<script>
import ThePagination from '../../components/ThePagination'

export default {
  name: 'MarathonSurveyRunnerReview',
  components: {
    ThePagination,
  },
  computed: {
    statusLabels () {
      return [
        {
          status: 'pending',
          text: this.$t ('pending'),
        },
        {
          status: 'rejected',
          text: this.$t ('rejected'),
        },
        {
          status: 'approved',
          text: this.$t ('approved'),
        },
      ]
    },
  },
  provide () {
    return {
      changePage: this.getRunners,
    }
  },
  data () {
    return {
      status: 'pending',
      runners: null,
    }
  },
  created () {
    this.getRunners ()
    console.log (this.statusLabels)
  },
  methods: {
    async getRunners () {
      this.runners = await this.runnersPlaza.getRunners(this.status)
    },
    runnerInfo (id) {
      this.$router.replace ('runner-detail/' + id)
    },
  },
}
</script>
