<template>
  <h3 v-if="!verified">工事中</h3>
</template>

<script>
export default {
  name: 'personal-score',
  data() {
    return {
      verified: false,
    }
  },
  created () {
    this.runnersPlaza.getRunner().then ((runner) => {
      if (runner.status === 'approved') {
        this.verified = true;
      }
    });
  },
}

</script>
